import { clearActivePreviewSession, writeActivePreviewSession, } from "../activePreviewSession.js";
import { reportHandoff } from "../analytics.js";
import { getConfig, hasCredentials } from "../config.js";
import { emitJson } from "../output.js";
import { positionalArgs } from "../parseArgs.js";
import { handleStudioError, openStudioTo } from "./openStudioTo.js";
export function buildTemplatePreviewUrl(serviceUrl, functionKey) {
    return `${serviceUrl}/studio/trace-functions/${encodeURIComponent(functionKey)}/template-preview`;
}
const ARGS = [{ name: "functionKey" }];
export async function runStartTemplatePreview(platform, pluginVersion) {
    const args = positionalArgs(ARGS);
    const functionKey = args[0];
    const config = getConfig();
    const apiKey = hasCredentials() ? config.apiKey : null;
    const serviceUrl = config.serviceUrl;
    const targetPath = `/studio/trace-functions/${encodeURIComponent(functionKey)}/template-preview`;
    let abort = () => { };
    try {
        const result = await openStudioTo(targetPath, {
            apiKey,
            serviceUrl,
            onLoginRequired: (sessionId, signInUrl) => {
                emitJson({ event: "auth-required", sessionId, signInUrl });
            },
            onAuthenticated: (sessionId) => {
                emitJson({ event: "authenticated", sessionId });
            },
            onEvent: (event) => {
                if (event.type === "studio:element-clicked") {
                    emitJson({
                        event: "click",
                        ts: new Date().toISOString(),
                        ...event.data,
                    });
                    return;
                }
                if (event.type === "focusChanged") {
                    emitJson({
                        event: "focus",
                        ts: new Date().toISOString(),
                        ...event.data,
                    });
                    return;
                }
                if (event.type === "studio:return-to-agent" ||
                    event.type === "studio:session-ended") {
                    console.log("Template preview closed [via studio].");
                    abort();
                }
            },
        });
        abort = result.abort;
        writeActivePreviewSession({
            sessionId: result.sessionId,
            serviceUrl,
        });
        const cleanupActiveSession = () => {
            try {
                clearActivePreviewSession();
            }
            catch { }
        };
        process.on("exit", cleanupActiveSession);
        const onSignal = () => {
            cleanupActiveSession();
            process.exit(0);
        };
        process.on("SIGINT", onSignal);
        process.on("SIGTERM", onSignal);
        process.on("SIGHUP", onSignal);
        await result.done;
        await reportHandoff(result.apiKey, pluginVersion, platform, {
            flow: "template.preview",
            wonBy: "studio",
            loopbackAvailable: false,
            ticketAvailable: false,
        });
        process.exit(0);
    }
    catch (err) {
        handleStudioError(err);
    }
}
